from typing import Optional

import torch



class DeepSeekActiveCacheBuilder:
    def __init__(self, cache, inference_config):
        self.cache = cache
        self.cfg = inference_config

    def capture_layer_input(
        self,
        layer_idx: int,
        attention_type: str,
        attention_module: torch.nn.Module,
        x_norm: torch.Tensor,
        position_ids: torch.Tensor,
        attention_mask: Optional[torch.Tensor],
    ) -> None:
        layer_cache = self.cache.layer_caches[layer_idx]

        if attention_type == "mha":
            if not isinstance(layer_cache, MHACache):
                raise TypeError("MHA attention requires MHACache.")
            if not all(hasattr(attention_module, name) for name in ("k_proj", "v_proj", "_shape_projection")):
                raise NotImplementedError("MHA parallel prefill requires k/v projection helpers.")
            layer_cache.reset()
            k = attention_module._shape_projection(attention_module.k_proj(x_norm))
            v = attention_module._shape_projection(attention_module.v_proj(x_norm))
            if getattr(attention_module, "rope", None) is not None:
                k = attention_module.rope(k, position_ids=position_ids, start_pos=0)
            layer_cache.append(k.transpose(1, 2), v.transpose(1, 2), position_ids)
            return

        if attention_type == "hca":
            if not isinstance(layer_cache, HCALayerCache):
                raise TypeError("HCA attention requires HCALayerCache.")
            if not hasattr(attention_module, "project_cache_states_full"):
                raise NotImplementedError("HCA parallel prefill requires project_cache_states_full.")
            states = attention_module.project_cache_states_full(x_norm)
            layer_cache.build_from_full_sequence(
                c=states["c"],
                z=states["z"],
                positions=position_ids,
                valid_mask=attention_mask,
                compressor_fn=attention_module.compress_hca_block_for_cache,
            )
            return

        if attention_type == "csa":
            if not isinstance(layer_cache, CSALayerCache):
                raise TypeError("CSA attention requires CSALayerCache.")
            if not hasattr(attention_module, "project_cache_states_full"):
                raise NotImplementedError("CSA parallel prefill requires project_cache_states_full.")
            states = attention_module.project_cache_states_full(x_norm)
            layer_cache.build_from_full_sequence(
                a_c=states["a_c"],
                b_c=states["b_c"],
                a_z=states["a_z"],
                b_z=states["b_z"],
                index_a_c=states["index_a_c"],
                index_b_c=states["index_b_c"],
                index_a_z=states["index_a_z"],
                index_b_z=states["index_b_z"],
                positions=position_ids,
                valid_mask=attention_mask,
                main_compressor_fn=attention_module.compress_csa_main_block_for_cache,
                index_compressor_fn=attention_module.compress_csa_index_block_for_cache,
                local_c=states.get("local_c"),
            )
            return

        raise NotImplementedError(f"Unsupported attention type for DeepSeek cache builder: {attention_type!r}")


# ==============================================================================
# inference/sampling.py
# ==============================================================================

import torch



def apply_repetition_penalty(
    logits: torch.Tensor,
    generated_ids: torch.Tensor,
    penalty: float | None,
) -> torch.Tensor:
    if penalty is None or penalty == 1.0:
        return logits
    if penalty <= 0:
        raise ValueError(f"penalty must be > 0, got {penalty}")

    logits = logits.clone()
    for batch_idx in range(logits.shape[0]):
        seen = torch.unique(generated_ids[batch_idx].to(device=logits.device, dtype=torch.long))
        token_logits = logits[batch_idx, seen]
        logits[batch_idx, seen] = torch.where(token_logits < 0, token_logits * penalty, token_logits / penalty)
    return logits


def top_k_filtering(logits: torch.Tensor, top_k: int | None) -> torch.Tensor:
    if top_k is None:
        return logits
    top_k = min(int(top_k), logits.shape[-1])
    values, _ = torch.topk(logits, k=top_k, dim=-1)
    cutoff = values[..., -1, None]
    return logits.masked_fill(logits < cutoff, float("-inf"))


def top_p_filtering(logits: torch.Tensor, top_p: float | None) -> torch.Tensor:
    if top_p is None or top_p >= 1.0:
        return logits
    sorted_logits, sorted_indices = torch.sort(logits, descending=True, dim=-1)
    probs = torch.softmax(sorted_logits, dim=-1)
    cumulative = torch.cumsum(probs, dim=-1)

    remove = cumulative > top_p
    remove[..., 1:] = remove[..., :-1].clone()
    remove[..., 0] = False

    filtered_sorted = sorted_logits.masked_fill(remove, float("-inf"))
    filtered = torch.empty_like(logits)
    filtered.scatter_(dim=-1, index=sorted_indices, src=filtered_sorted)
    return filtered


def _safe_argmax(logits: torch.Tensor) -> torch.Tensor:
    clean_logits = torch.nan_to_num(logits, nan=float("-inf"), posinf=1e30, neginf=-1e30)
    return torch.argmax(clean_logits, dim=-1, keepdim=True)


def sample_next_token(
    logits: torch.Tensor,
    config: InferenceConfig,
    generated_ids: torch.Tensor | None = None,
) -> torch.Tensor:
    config.validate()
    if logits.dim() != 2:
        raise ValueError(f"sample_next_token expects logits [B,V], got {tuple(logits.shape)}")

    if not torch.isfinite(logits).all():
        return _safe_argmax(logits)

    if generated_ids is not None:
        logits = apply_repetition_penalty(logits, generated_ids, config.repetition_penalty)

    if not config.do_sample:
        return _safe_argmax(logits)

    logits = logits / config.temperature
    logits = top_k_filtering(logits, config.top_k)
    logits = top_p_filtering(logits, config.top_p)

    probs = torch.softmax(logits, dim=-1)
    valid = torch.isfinite(probs).all(dim=-1) & (probs.sum(dim=-1) > 0)
    if not bool(valid.all().item()):
        return _safe_argmax(logits)

    return torch.multinomial(probs, num_samples=1)


# ==============================================================================
# inference/mtp_decode.py
# ==============================================================================

from typing import Any, Optional

import torch



@torch.no_grad()
def mtp_draft_from_hidden(
    model: torch.nn.Module,
    hidden_states: Optional[torch.Tensor],
    inference_config: Optional[InferenceConfig] = None,
) -> dict[str, Any]:
    cfg = inference_config or InferenceConfig()
    cfg.validate()

    mtp_head = getattr(model, "mtp_head", None)
    if hidden_states is None or mtp_head is None or not getattr(model, "use_mtp", False):
        return {
            "enabled": False,
            "mtp_logits": None,
            "draft_token_ids": None,
            "draft_confidence": None,
            "is_speculative_decode": False,
        }

    outputs = mtp_head(hidden_states[:, -1:, :], mtp_labels=None, return_aux=False)
    logits = outputs["mtp_logits"]
    max_tokens = cfg.max_mtp_draft_tokens or logits.shape[1]
    max_tokens = min(max_tokens, logits.shape[1])
    draft_logits = logits[:, :max_tokens, -1, :]
    draft_probs = torch.softmax(draft_logits.float(), dim=-1)
    draft_confidence, draft_ids = torch.max(draft_probs, dim=-1)

    return {
        "enabled": bool(cfg.use_mtp_draft),
        "accept_mode": cfg.mtp_accept_mode,
        "mtp_logits": logits,
        "draft_token_ids": draft_ids,
        "draft_confidence": draft_confidence,
        "is_speculative_decode": False,
    }


