# inference/decode.py
# ==============================================================================

from typing import Any, Optional

import torch



def configure_cache_metadata(cache: DeepSeekV4InferenceCache, cfg: InferenceConfig) -> None:
    cache.metadata["cache_mode"] = cfg.cache_mode
    cache.metadata["active_decode"] = cfg.cache_mode in {"mha_decode", "deepseek_decode"}
    cache.metadata["logits_from_cache"] = cfg.cache_mode in {"mha_decode", "deepseek_decode"}
    if cfg.cache_mode == "mha_decode":
        cache.metadata["cache_population"] = "active_mha_kv"
    elif cfg.cache_mode == "deepseek_decode":
        cache.metadata["cache_population"] = cfg.deepseek_cache_population
    else:
        cache.metadata["cache_population"] = "embedding_proxy"


def _layer_hidden_for_cache(
    model: torch.nn.Module,
    input_ids_t: torch.Tensor,
    cache: DeepSeekV4InferenceCache,
) -> torch.Tensor:
    return token_hidden_state(
        model,
        input_ids_t,
        device=cache.device,
        dtype=cache.dtype,
    )


def update_cache_with_token(
    model: torch.nn.Module,
    input_ids_t: torch.Tensor,
    cache: DeepSeekV4InferenceCache,
    position_ids_t: Optional[torch.Tensor] = None,
    attention_mask_t: Optional[torch.Tensor] = None,
    inference_config: Optional[InferenceConfig] = None,
) -> DeepSeekV4InferenceCache:
    cfg = inference_config or InferenceConfig()
    cfg.validate()
    configure_cache_metadata(cache, cfg)

    input_ids_t = input_ids_t.to(device=cache.device, dtype=torch.long)
    if input_ids_t.dim() != 2 or input_ids_t.shape[1] != 1:
        raise ValueError(f"input_ids_t must have shape [B,1], got {tuple(input_ids_t.shape)}")

    position_ids_t = normalize_position_ids(
        position_ids_t,
        batch_size=input_ids_t.shape[0],
        seq_len=1,
        start_pos=cache.tokens_seen,
        device=cache.device,
    )
    pad_token_id = cfg.pad_token_id
    if pad_token_id is None:
        pad_token_id = getattr(model, "pad_token_id", None)

    valid_mask_t = (
        attention_mask_t.to(device=cache.device).bool()
        if attention_mask_t is not None
        else default_valid_mask(input_ids_t, pad_token_id)
    )
    hidden = _layer_hidden_for_cache(model, input_ids_t, cache)
    index_dim = int(getattr(getattr(model, "config", None), "indexer_dim", hidden.shape[-1]))

    for layer_cache in cache.layer_caches:
        if isinstance(layer_cache, MHACache):
            k_t, v_t = hidden_to_mha_kv(model, hidden)
            layer_cache.append(k_t, v_t, position_ids_t)
            layer_cache.crop(cfg.max_cache_length)
        elif isinstance(layer_cache, HCALayerCache):
            layer_cache.append_token_state(hidden, hidden, position_ids_t, valid_mask_t)
            if cfg.compress_on_block_ready:
                layer_cache.flush_ready_blocks()
        elif isinstance(layer_cache, CSALayerCache):
            index_state = hidden_to_index_state(hidden, index_dim)
            layer_cache.append_token_state(
                a_c_t=hidden,
                b_c_t=hidden,
                a_z_t=hidden,
                b_z_t=hidden,
                index_a_c_t=index_state,
                index_b_c_t=index_state,
                index_a_z_t=index_state,
                index_b_z_t=index_state,
                position_t=position_ids_t,
                valid_mask_t=valid_mask_t,
            )
            if cfg.compress_on_block_ready:
                layer_cache.flush_ready_blocks()

    cache.append_input_ids(input_ids_t, valid_mask_t.long())
    cache.crop_sequence(cfg.max_cache_length)
    return cache


def _full_forward_decode(
    model: torch.nn.Module,
    cache: DeepSeekV4InferenceCache,
    *,
    return_aux: bool,
) -> dict[str, Any]:
    if cache.sequence_ids is None:
        raise ValueError("cache.sequence_ids is empty; call prefill or update_cache_with_token first.")

    max_context = context_window_for_model(model, None)
    input_ids = cache.sequence_ids[:, -max_context:]
    attention_mask = cache.attention_mask[:, -input_ids.shape[1] :] if cache.attention_mask is not None else None
    outputs = model(
        input_ids=input_ids,
        attention_mask=attention_mask,
        return_aux=return_aux,
    )
    return {
        "logits": outputs["logits"][:, -1:, :],
        "hidden_states": outputs.get("hidden_states", None),
        "aux": outputs.get("aux", {}),
    }


@torch.no_grad()
def decode_step(
    model: torch.nn.Module,
    input_ids_t: torch.Tensor,
    cache: DeepSeekV4InferenceCache,
    position_ids_t: Optional[torch.Tensor] = None,
    inference_config: Optional[InferenceConfig] = None,
    return_aux: bool = False,
) -> dict[str, Any]:
    cfg = inference_config or InferenceConfig()
    cfg.validate()

    if cache is None:
        raise ValueError("decode_step requires a DeepSeekV4InferenceCache instance.")

    if cfg.cache_mode in {"mha_decode", "deepseek_decode"}:
        model_cfg = getattr(model, "config", None)
        if cfg.cache_mode == "mha_decode" and getattr(model_cfg, "attention_type", None) != "mha":
            raise NotImplementedError("cache_mode='mha_decode' only supports attention_type='mha'.")
        if not hasattr(model, "forward_decode"):
            raise NotImplementedError("Model does not expose forward_decode for active cached decoding.")

        configure_cache_metadata(cache, cfg)
        decoded = model.forward_decode(
            input_ids_t=input_ids_t,
            cache=cache,
            position_ids_t=position_ids_t,
            attention_mask_t=None,
            return_aux=return_aux,
        )
    else:
        update_cache_with_token(
            model,
            input_ids_t=input_ids_t,
            cache=cache,
            position_ids_t=position_ids_t,
            inference_config=cfg,
        )
        decoded = _full_forward_decode(model, cache, return_aux=return_aux)
        decoded["cache"] = cache
        decoded["aux"] = decoded.get("aux", {})

    if return_aux:
        decoded["aux"]["cache_summary"] = cache.cache_summary()
    return decoded


def next_position_ids(cache: DeepSeekV4InferenceCache) -> torch.Tensor:
    return torch.full(
        (cache.batch_size, 1),
        fill_value=int(cache.tokens_seen),
        device=cache.device,
        dtype=torch.long,
    )


def prepare_input_ids(input_ids: torch.Tensor, model: torch.nn.Module, cfg: InferenceConfig) -> torch.Tensor:
    device = resolve_device(model, cfg.device)
    return input_ids.to(device=device, dtype=torch.long)


# ==============================================================================
# inference/prefill.py
# ==============================================================================

from typing import Any, Optional

import torch



@torch.no_grad()
def prefill(
    model: torch.nn.Module,
    input_ids: torch.Tensor,
    attention_mask: Optional[torch.Tensor] = None,
    position_ids: Optional[torch.Tensor] = None,
    inference_config: Optional[InferenceConfig] = None,
    return_aux: bool = False,
) -> dict[str, Any]:
    cfg = inference_config or InferenceConfig()
    cfg.validate()

    device = resolve_device(model, cfg.device)
    cache_dtype = resolve_cache_dtype(cfg.cache_dtype)
    input_ids = input_ids.to(device=device, dtype=torch.long)
    if input_ids.dim() != 2:
        raise ValueError(f"input_ids must have shape [B,T], got {tuple(input_ids.shape)}")
    if input_ids.shape[1] == 0:
        raise ValueError("prefill requires at least one prompt token.")

    if attention_mask is not None:
        attention_mask = attention_mask.to(device=device)

    batch_size, seq_len = input_ids.shape
    position_ids = normalize_position_ids(
        position_ids,
        batch_size=batch_size,
        seq_len=seq_len,
        device=device,
    )
    cache = build_inference_cache(
        model,
        batch_size=batch_size,
        device=device,
        dtype=cache_dtype,
        local_window_size=cfg.local_window_size,
    )
    configure_cache_metadata(cache, cfg)

    if cfg.cache_mode == "deepseek_decode" and cfg.deepseek_prefill_mode == "parallel":
        if not hasattr(model, "prefill_decode_cache"):
            raise NotImplementedError(
                "cache_mode='deepseek_decode' with deepseek_prefill_mode='parallel' "
                "requires model.prefill_decode_cache(...)."
            )
        out = model.prefill_decode_cache(
            input_ids=input_ids,
            cache=cache,
            attention_mask=attention_mask,
            position_ids=position_ids,
            inference_config=cfg,
            return_aux=return_aux,
        )
        if return_aux:
            aux = out.get("aux", {})
            aux["cache_summary"] = out["cache"].cache_summary()
            out["aux"] = aux
        return out

    if cfg.cache_mode in {"mha_decode", "deepseek_decode"}:
        if getattr(getattr(model, "config", None), "attention_type", None) != "mha":
            if cfg.cache_mode == "mha_decode":
                raise NotImplementedError("cache_mode='mha_decode' only supports attention_type='mha'.")
        logits_steps = []
        hidden_states = None
        aux = {}
        for idx in range(seq_len):
            mask_t = attention_mask[:, idx : idx + 1] if attention_mask is not None else None
            out = model.forward_decode(
                input_ids_t=input_ids[:, idx : idx + 1],
                cache=cache,
                position_ids_t=position_ids[:, idx : idx + 1],
                attention_mask_t=mask_t,
                return_aux=return_aux,
            )
            cache = out["cache"]
            logits_steps.append(out["logits"])
            hidden_states = out.get("hidden_states")
            aux = out.get("aux", {})

        full_logits = torch.cat(logits_steps, dim=1)
        if return_aux:
            aux["cache_summary"] = cache.cache_summary()
        return {
            "logits": full_logits[:, -1:, :],
            "full_logits": full_logits,
            "hidden_states": hidden_states,
            "cache": cache,
            "aux": aux if return_aux else {},
        }

    for idx in range(seq_len):
        mask_t = attention_mask[:, idx : idx + 1] if attention_mask is not None else None
        update_cache_with_token(
            model,
            input_ids_t=input_ids[:, idx : idx + 1],
            cache=cache,
            position_ids_t=position_ids[:, idx : idx + 1],
            attention_mask_t=mask_t,
            inference_config=cfg,
        )

    outputs = model(
        input_ids=input_ids,
        attention_mask=attention_mask,
        position_ids=position_ids,
        return_aux=return_aux,
    )
    aux = outputs.get("aux", {}) if return_aux else {}
    if return_aux:
        aux["cache_summary"] = cache.cache_summary()

    return {
        "logits": outputs["logits"][:, -1:, :],
        "full_logits": outputs["logits"],
        "hidden_states": outputs.get("hidden_states", None),
        "cache": cache,
        "aux": aux,
    }


def empty_cache_like_prefill(
    model: torch.nn.Module,
    input_ids: torch.Tensor,
    inference_config: Optional[InferenceConfig] = None,
) -> DeepSeekV4InferenceCache:
    cfg = inference_config or InferenceConfig()
    device = resolve_device(model, cfg.device)
    return build_inference_cache(
        model,
        batch_size=int(input_ids.shape[0]),
        device=device,
        dtype=resolve_cache_dtype(cfg.cache_dtype),
        local_window_size=cfg.local_window_size,
    )


# ==============================================================================
# inference/metrics.py
# ==============================================================================

import time
from typing import Any, Optional

import torch



def cache_memory_bytes(cache: Any) -> int:
    if cache is None:
        return 0
    if hasattr(cache, "memory_bytes"):
        return int(cache.memory_bytes())
    return 0


def cache_summary(cache: Any) -> dict[str, Any]:
    if cache is None:
        return {}
    if hasattr(cache, "cache_summary"):
        return cache.cache_summary()
    return {"cache_memory_bytes": cache_memory_bytes(cache)}


def generation_speed_metrics(start_time: float, end_time: float, num_tokens: int) -> dict[str, float]:
    elapsed = max(float(end_time) - float(start_time), 0.0)
    return {
        "elapsed_seconds": elapsed,
        "num_generated_tokens": float(num_tokens),
        "tokens_per_second": float(num_tokens) / elapsed if elapsed > 0 else 0.0,
    }


@torch.no_grad()
def compare_full_vs_cached_logits(
    model: torch.nn.Module,
    input_ids: torch.Tensor,
    inference_config: Optional[InferenceConfig] = None,
    atol: float = 1e-4,
    rtol: float = 1e-4,
) -> dict[str, Any]:
    cfg = inference_config or InferenceConfig(do_sample=False)
    cfg.validate()
    was_training = model.training
    model.eval()

    full = model(input_ids=input_ids)["logits"]
    cached_positions = []
    max_diff = 0.0
    cache = None
    try:
        for idx in range(input_ids.shape[1]):
            out = prefill(
                model,
                input_ids=input_ids[:, : idx + 1],
                inference_config=cfg,
                return_aux=False,
            )
            cache = out["cache"]
            cached = out["logits"][:, -1, :]
            target = full[:, idx, :]
            diff = torch.max(torch.abs(cached - target)).item()
            max_diff = max(max_diff, float(diff))
            cached_positions.append(bool(torch.allclose(cached, target, atol=atol, rtol=rtol)))
    finally:
        if was_training:
            model.train()

    return {
        "allclose": all(cached_positions),
        "per_position_allclose": cached_positions,
        "max_abs_diff": max_diff,
        "atol": atol,
        "rtol": rtol,
        "cache_summary": cache_summary(cache),
    }


def now() -> float:
    return time.perf_counter()


# ==============================================================================
# inference/generate.py
# ==============================================================================

from typing import Any, Optional

import torch



@torch.no_grad()
def generate(
    model: torch.nn.Module,
    input_ids: torch.Tensor,
    inference_config: InferenceConfig,
    attention_mask: Optional[torch.Tensor] = None,
    return_dict: bool = True,
) -> dict[str, Any] | torch.Tensor:
    inference_config.validate()
    was_training = model.training
    model.eval()

    device = resolve_device(model, inference_config.device)
    input_ids = input_ids.to(device=device, dtype=torch.long)
    if attention_mask is not None:
        attention_mask = attention_mask.to(device=device)

    start = now()
    prompt_len = int(input_ids.shape[1])
    prefill_start = now()
    prefill_out = prefill(
        model,
        input_ids=input_ids,
        attention_mask=attention_mask,
        inference_config=inference_config,
        return_aux=inference_config.use_mtp_draft or inference_config.return_cache_stats,
    )
    prefill_end = now()

    cache = prefill_out["cache"]
    sequences = input_ids
    logits = prefill_out["logits"][:, -1, :]
    scores: list[torch.Tensor] = []
    mtp_drafts: list[dict[str, Any]] = []
    finished = torch.zeros(input_ids.shape[0], device=device, dtype=torch.bool)

    hidden_states = prefill_out.get("hidden_states")
    if inference_config.use_mtp_draft:
        mtp_drafts.append(mtp_draft_from_hidden(model, hidden_states, inference_config))

    decode_time = 0.0
    for _ in range(inference_config.max_new_tokens):
        if inference_config.return_cache_stats:
            scores.append(logits.detach().cpu())

        next_token = sample_next_token(logits, inference_config, sequences)
        if inference_config.eos_token_id is not None:
            eos = int(inference_config.eos_token_id)
            if inference_config.pad_token_id is not None:
                pad = torch.full_like(next_token, int(inference_config.pad_token_id))
                next_token = torch.where(finished.unsqueeze(1), pad, next_token)
            finished = finished | next_token.squeeze(1).eq(eos)

        sequences = torch.cat([sequences, next_token], dim=1)
        if bool(finished.all().item()):
            break

        step_start = now()
        decoded = decode_step(
            model,
            input_ids_t=next_token,
            cache=cache,
            inference_config=inference_config,
            return_aux=inference_config.use_mtp_draft or inference_config.return_cache_stats,
        )
        decode_time += now() - step_start
        cache = decoded["cache"]
        logits = decoded["logits"][:, -1, :]
        hidden_states = decoded.get("hidden_states")
        if inference_config.use_mtp_draft:
            mtp_drafts.append(mtp_draft_from_hidden(model, hidden_states, inference_config))

    end = now()
    num_generated = int(sequences.shape[1] - prompt_len)
    output = {
        "sequences": sequences,
        "scores": scores if inference_config.return_cache_stats else None,
        "cache": cache,
        "cache_stats": cache_summary(cache) if inference_config.return_cache_stats else None,
        "num_generated_tokens": num_generated,
        "prompt_length": prompt_len,
        "prefill_time": prefill_end - prefill_start,
        "decode_time": decode_time,
        "decode_time_per_token": decode_time / max(num_generated, 1),
        "speed": generation_speed_metrics(start, end, num_generated),
        "mtp_drafts": mtp_drafts if inference_config.use_mtp_draft else None,
    }

    if was_training:
        model.train()

    if return_dict:
        return output
    return sequences


@torch.no_grad()
def inference_autoregresive(
    model: torch.nn.Module,
    prompt: str | list[int] | torch.Tensor,
    tokenizer: Optional[Any] = None,
    **generation_kwargs,
) -> dict[str, Any]:
    config = InferenceConfig(**generation_kwargs)
    input_ids = encode_prompt(prompt, tokenizer=tokenizer)
    output = generate(
        model=model,
        input_ids=input_ids,
        inference_config=config,
        return_dict=True,
    )
    output["text"] = decode_token_ids(output["sequences"], tokenizer=tokenizer)
    return output


inference_autoregressive = inference_autoregresive


